#include <stdio.h>
#include <stdlib.h>

// iterative stack for DFS to avoid recursion limits
typedef struct {int r; int c;} Node;

void floodFill(int **grid, int n, int sr, int sc) {
    if (grid[sr][sc] != 1) return;
    Node *stack = (Node*)malloc(n*n * sizeof(Node));
    int top = 0;
    stack[top++] = (Node){sr, sc};
    while (top) {
        Node cur = stack[--top];
        int r = cur.r, c = cur.c;
        if (r < 0 || r >= n || c < 0 || c >= n) continue;
        if (grid[r][c] != 1) continue;
        grid[r][c] = 0; // mark as visited / non‑enclave
        // push neighbours
        stack[top++] = (Node){r+1, c};
        stack[top++] = (Node){r-1, c};
        stack[top++] = (Node){r, c+1};
        stack[top++] = (Node){r, c-1};
    }
    free(stack);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int **grid = (int**)malloc(n * sizeof(int*));
        for (int i = 0; i < n; ++i) {
            grid[i] = (int*)malloc(n * sizeof(int));
            for (int j = 0; j < n; ++j) scanf("%d", &grid[i][j]);
        }
        // flood from border land cells
        for (int i = 0; i < n; ++i) {
            floodFill(grid, n, i, 0);
            floodFill(grid, n, i, n-1);
        }
        for (int j = 0; j < n; ++j) {
            floodFill(grid, n, 0, j);
            floodFill(grid, n, n-1, j);
        }
        long long enclaved = 0;
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                if (grid[i][j] == 1) ++enclaved;
        printf("%lld\n", enclaved);
        for (int i = 0; i < n; ++i) free(grid[i]);
        free(grid);
    }
    return 0;
}

