#include <bits/stdc++.h>
using namespace std;

void dfs(int r, int c, int n, vector<vector<int>>& g) {
    if (r < 0 || r >= n || c < 0 || c >= n || g[r][c] != 1) return;
    g[r][c] = 0;
    dfs(r+1, c, n, g);
    dfs(r-1, c, n, g);
    dfs(r, c+1, n, g);
    dfs(r, c-1, n, g);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int n; cin>>n;
        vector<vector<int>> grid(n, vector<int>(n));
        for(int i=0;i<n;++i) for(int j=0;j<n;++j) cin>>grid[i][j];
        for(int i=0;i<n;++i){ dfs(i,0,n,grid); dfs(i,n-1,n,grid); }
        for(int j=0;j<n;++j){ dfs(0,j,n,grid); dfs(n-1,j,n,grid); }
        long long ans=0;
        for(int i=0;i<n;++i) for(int j=0;j<n;++j) if(grid[i][j]==1) ++ans;
        cout<<ans<<"\n";
    }
    return 0;
}

