import java.io.*;
import java.util.*;

public class Main {
    static void dfs(int r, int c, int n, int[][] g) {
        if (r < 0 || r >= n || c < 0 || c >= n || g[r][c] != 1) return;
        g[r][c] = 0;
        dfs(r+1, c, n, g);
        dfs(r-1, c, n, g);
        dfs(r, c+1, n, g);
        dfs(r, c-1, n, g);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int n = Integer.parseInt(br.readLine().trim());
            int[][] grid = new int[n][n];
            for (int i = 0; i < n; i++) {
                st = new StringTokenizer(br.readLine());
                for (int j = 0; j < n; j++) grid[i][j] = Integer.parseInt(st.nextToken());
            }
            for (int i = 0; i < n; i++) { dfs(i,0,n,grid); dfs(i,n-1,n,grid); }
            for (int j = 0; j < n; j++) { dfs(0,j,n,grid); dfs(n-1,j,n,grid); }
            long ans = 0;
            for (int i = 0; i < n; i++)
                for (int j = 0; j < n; j++)
                    if (grid[i][j] == 1) ans++;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

